import dev.langchain4j.data.audio.Audio;
import java.util.HashSet;
import java.util.Set;

public class AudioEqualityRepro {
    public static void main(String[] args) {
        byte[] data1 = new byte[] {1, 2, 3};
        byte[] data2 = new byte[] {1, 2, 3};

        Audio audio1 = Audio.builder().binaryData(data1).mimeType("audio/wav").build();
        Audio audio2 = Audio.builder().binaryData(data2).mimeType("audio/wav").build();

        if (!audio1.equals(audio2)) {
            throw new AssertionError("Audio objects with identical byte contents should be equal");
        }
        if (audio1.hashCode() != audio2.hashCode()) {
            throw new AssertionError("Audio objects with identical byte contents should have equal hash codes");
        }
        Set<Audio> set = new HashSet<>();
        set.add(audio1);
        if (!set.contains(audio2)) {
            throw new AssertionError("HashSet should find equivalent Audio by byte contents");
        }
    }
}
