import dev.langchain4j.data.audio.Audio;
import java.util.HashSet;
import java.util.Set;

public class AudioEqualityRepro {
    public static void main(String[] args) {
        assertEquivalent(
                Audio.builder().binaryData(new byte[] {1, 2, 3}).mimeType("audio/wav").build(),
                Audio.builder().binaryData(new byte[] {1, 2, 3}).mimeType("audio/wav").build(),
                "same byte contents");

        assertNotEquivalent(
                Audio.builder().binaryData(new byte[] {1, 2, 3}).mimeType("audio/wav").build(),
                Audio.builder().binaryData(new byte[] {1, 2, 4}).mimeType("audio/wav").build(),
                "different byte contents");

        assertEquivalent(
                Audio.builder().mimeType("audio/wav").build(),
                Audio.builder().mimeType("audio/wav").build(),
                "both binaryData null");

        assertNotEquivalent(
                Audio.builder().binaryData(new byte[] {1}).mimeType("audio/wav").build(),
                Audio.builder().binaryData(null).mimeType("audio/wav").build(),
                "one binaryData null");

        assertEquivalent(
                Audio.builder().url("https://example.com/audio.wav").base64Data("AQID").binaryData(new byte[] {1, 2, 3}).mimeType("audio/wav").build(),
                Audio.builder().url("https://example.com/audio.wav").base64Data("AQID").binaryData(new byte[] {1, 2, 3}).mimeType("audio/wav").build(),
                "all fields same including copied bytes");
    }

    private static void assertEquivalent(Audio left, Audio right, String label) {
        if (!left.equals(right)) {
            throw new AssertionError(label + ": expected equality");
        }
        if (left.hashCode() != right.hashCode()) {
            throw new AssertionError(label + ": expected equal hash codes");
        }
        Set<Audio> set = new HashSet<>();
        set.add(left);
        if (!set.contains(right)) {
            throw new AssertionError(label + ": expected HashSet lookup to succeed");
        }
    }

    private static void assertNotEquivalent(Audio left, Audio right, String label) {
        if (left.equals(right)) {
            throw new AssertionError(label + ": expected inequality");
        }
    }
}
